app.get("/hello/:name", (ctx) => {
  const { name } = ctx.params;             // route params
  const greeting = ctx.query("greeting");   // ?greeting=...
  ctx.headers.set("X-Request-Id", crypto.randomUUID());
  return ctx.json({ message: `${greeting ?? "hi"}, ${name}` });
});

